      this.activeTab = 'dashboard';
      this.newRoute = {
        source: '',
        destination: ''
      };
      this.assignRoute = {};
      this.cancelReason = {};
      this.error = '';
      this.success = '';
      this.today = new Date().toISOString().slice(0, 10);
      this.newBus = {
        registrationNumber: '',
        busName: '',
        busType: 'AC Seater',
        departureTime: '09:00',
        arrivalTime: '',
        travelDate: new Date().toISOString().slice(0, 10),
        totalSeats: 40,
        price: 500,
        routeId: '',
        operatorId: null,
        seatLayout: ''
      };
    }
